let filtered=workers.filter(r=>{if(statusFilter!=='all'&&r.worker_status!==statusFilter)return false;if(depFilter&&!(r.dependents_count>0))return false;if(q){const s=q.toLowerCase();return(r.name_ar||'').includes(s)||(r.name_en||'').toLowerCase().includes(s)||(r.iqama_number||'').includes(s)||(r.worker_number||'').includes(s)||(r.phone||'').includes(s)};return true})
