{tab==='iqama'&&<button onClick={()=>{setForm({facility_id:'',worker_id:'',iqama_issue_date:'',iqama_expiry_date:'',duration_months:'',notes:''});setPop('iqama')}} style={bS}>+ {T('\u0625\u0642\u0627\u0645\u0629','Iqama')}</button>}
