{(r.gosi_salary||r.qiwa_salary)?<div style={{display:'flex',borderTop:'1px solid rgba(255,255,255,.03)',padding:'6px 12px',gap:12,background:'rgba(201,168,76,.02)'}}>{r.gosi_salary&&<span style={{fontSize:9,color:'rgba(201,168,76,.5)'}}>{T('\u062a\u0623\u0645\u064a\u0646\u0627\u062a:','GOSI:')} <b style={{color:C.gold}}>{nm(r.gosi_salary)}</b></span>}{r.qiwa_salary&&<span style={{fontSize:9,color:'rgba(52,131,180,.5)'}}>{T('\u0642\u0648\u0649:','Qiwa:')} <b style={{color:C.blue}}>{nm(r.qiwa_salary)}</b></span>}</div>:null}
